from collections import defaultdict
import heapq

def critical_path_method(tasks: dict, dependencies: dict) -> dict:
    successors = defaultdict(list)
    in_degree = {t: 0 for t in tasks}

    for task, prereqs in dependencies.items():
        in_degree[task] = len(prereqs)
        for prereq in prereqs:
            successors[prereq].append(task)

    # Topological sort with min-heap for alphabetical tie-breaking
    heap = [t for t in tasks if in_degree[t] == 0]
    heapq.heapify(heap)
    topo_order = []

    while heap:
        task = heapq.heappop(heap)
        topo_order.append(task)
        for succ in successors[task]:
            in_degree[succ] -= 1
            if in_degree[succ] == 0:
                heapq.heappush(heap, succ)

    # Forward pass: Earliest Start (ES) and Earliest Finish (EF)
    es = {t: 0 for t in tasks}
    ef = {}
    for task in topo_order:
        prereqs = dependencies.get(task, [])
        if prereqs:
            es[task] = max(ef[p] for p in prereqs)
        ef[task] = es[task] + tasks[task]

    project_duration = max(ef.values())

    # Backward pass: Latest Finish (LF) and Latest Start (LS)
    lf = {t: project_duration for t in tasks}
    ls = {}
    for task in reversed(topo_order):
        succs = successors[task]
        if succs:
            lf[task] = min(ls[s] for s in succs)
        ls[task] = lf[task] - tasks[task]

    slack = {t: ls[t] - es[t] for t in tasks}
    critical_path = [t for t in topo_order if slack[t] == 0]

    return {
        'project_duration': project_duration,
        'critical_path': critical_path,
        'slack': slack
    }
